import { setup, assign } from 'xstate';

interface Ctx {
  fireAt: number | null;
  snoozeMs: number;
}
type Ev =
  | { type: 'SCHEDULE'; at: number }
  | { type: 'FIRE' }
  | { type: 'SNOOZE' }
  | { type: 'DISMISS' };

export const alarmMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: {
    UNTIL_FIRE: ({ context }: { context: Ctx }) => Math.max(0, (context.fireAt ?? 0) - Date.now()),
    SNOOZE_FOR: ({ context }: { context: Ctx }) => context.snoozeMs
  },
  actions: {
    setFire: assign({ fireAt: ({ event }) => (event.type === 'SCHEDULE' ? event.at : null) }),
    clearFire: assign({ fireAt: () => null })
  }
}).createMachine({
  id: 'alarm',
  context: { fireAt: null, snoozeMs: 5 * 60_000 },
  initial: 'idle',
  states: {
    idle: {
      on: { SCHEDULE: { target: 'waiting', actions: 'setFire' } }
    },
    waiting: {
      after: { UNTIL_FIRE: 'ringing' },
      on: { DISMISS: { target: 'idle', actions: 'clearFire' } }
    },
    ringing: {
      on: {
        SNOOZE: 'snoozed',
        DISMISS: { target: 'idle', actions: 'clearFire' }
      }
    },
    snoozed: {
      after: { SNOOZE_FOR: 'ringing' },
      on: { DISMISS: { target: 'idle', actions: 'clearFire' } }
    }
  }
});
```

Track the snooze count in context and use a guard on SNOOZE to fall through to dismissed once the cap is hit.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { snoozes: number }
type Ev = { type: 'RING' } | { type: 'SNOOZE' } | { type: 'DISMISS' };

export const cappedReminder = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { SNOOZE: 60_000 },
  guards: {
    canSnooze: ({ context }) => context.snoozes < 3
  }
}).createMachine({
  id: 'cappedReminder',
  context: { snoozes: 0 },
  initial: 'waiting',
  states: {
    waiting: { on: { RING: 'ringing' } },
    ringing: {
      on: {
        SNOOZE: [
          { guard: 'canSnooze', target: 'snoozed', actions: assign({ snoozes: ({ context }) => context.snoozes + 1 }) },
          { target: 'dismissed' }
        ],
        DISMISS: 'dismissed'
      }
    },
    snoozed: { after: { SNOOZE: 'ringing' } },
    dismissed: { type: 'final' }
  }
});
```

A recurring alarm lives in a waiting state whose `after` delay reads the next fire time from context. When the alarm rings and is dismissed, we recompute the next fire time (24 hours later) and re-enter waiting so the timer restarts with the new delay.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { nextAt: number }
type Ev = { type: 'DISMISS' } | { type: 'FIRE' };

const DAY = 24 * 60 * 60 * 1000;

export const dailyAlarm = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: {
    TIL_NEXT: ({ context }: { context: Ctx }) => Math.max(0, context.nextAt - Date.now())
  },
  actions: {
    scheduleNext: assign({ nextAt: ({ context }) => context.nextAt + DAY })
  }
}).createMachine({
  id: 'dailyAlarm',
  context: { nextAt: Date.now() + DAY },
  initial: 'waiting',
  states: {
    waiting: {
      after: { TIL_NEXT: 'ringing' }
    },
    ringing: {
      on: { DISMISS: { target: 'waiting', actions: 'scheduleNext' } }
    }
  }
});
```

