import { setup, assign, fromPromise } from 'xstate';

interface Change { id: string; body: string }
interface Ctx {
  queue: Change[];
  attempt: number;
  lastError: string | null;
}
type Ev =
  | { type: 'EDIT'; change: Change }
  | { type: 'SYNCED' }
  | { type: 'RETRY' };

export const cloudSyncMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    upload: fromPromise<void, { queue: Change[] }>(async ({ input }) => {
      if (input.queue.length === 0) return;
      // POST input.queue to server
    })
  },
  delays: {
    BACKOFF: ({ context }: { context: Ctx }) => Math.min(30_000, 1_000 * 2 ** context.attempt)
  },
  actions: {
    enqueue: assign({ queue: ({ context, event }) => (event.type === 'EDIT' ? [...context.queue, event.change] : context.queue) }),
    clearQueue: assign({ queue: () => [], attempt: () => 0, lastError: () => null }),
    recordError: assign({
      attempt: ({ context }) => context.attempt + 1,
      lastError: ({ event }) => ('error' in event ? String((event as { error: unknown }).error) : 'unknown')
    })
  }
}).createMachine({
  id: 'cloudSync',
  context: { queue: [], attempt: 0, lastError: null },
  initial: 'synced',
  states: {
    synced: { on: { EDIT: { target: 'queued', actions: 'enqueue' } } },
    queued: {
      on: { EDIT: { actions: 'enqueue' } },
      always: 'uploading'
    },
    uploading: {
      invoke: {
        src: 'upload',
        input: ({ context }) => ({ queue: context.queue }),
        onDone: { target: 'synced', actions: 'clearQueue' },
        onError: { target: 'error', actions: 'recordError' }
      }
    },
    error: {
      after: { BACKOFF: 'uploading' },
      on: { RETRY: 'uploading', EDIT: { target: 'queued', actions: 'enqueue' } }
    }
  }
});
```

Invoke a fromCallback actor that sends back ONLINE when `window` fires the online event, and transition from an offline state into uploading on that event.

```typescript
import { setup, fromCallback } from 'xstate';

type Parent = { type: 'ONLINE' } | { type: 'OFFLINE' };

export const netSync = setup({
  types: { context: {} as {}, events: {} as Parent },
  actors: {
    netWatcher: fromCallback<Parent>(({ sendBack }) => {
      const on = () => sendBack({ type: 'ONLINE' });
      const off = () => sendBack({ type: 'OFFLINE' });
      // window.addEventListener('online', on) / ('offline', off)
      return () => {
        void on; void off;
      };
    })
  }
}).createMachine({
  id: 'netSync',
  initial: 'offline',
  invoke: { src: 'netWatcher' },
  states: {
    offline: { on: { ONLINE: 'uploading' } },
    uploading: { on: { OFFLINE: 'offline' } }
  }
});
```

The dirty flag lives in context as a boolean derived from queue size. We set it on every EDIT and clear it on successful upload. The UI reads `actor.getSnapshot().context.dirty`, so we never have to emit a separate event for it.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Ctx { queued: number; dirty: boolean }
type Ev = { type: 'EDIT' } | { type: 'UPLOAD' };

export const dirtySync = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    push: fromPromise<void, { queued: number }>(async () => {
      // send to server
    })
  }
}).createMachine({
  id: 'dirtySync',
  context: { queued: 0, dirty: false },
  initial: 'clean',
  states: {
    clean: { on: { EDIT: { target: 'dirty', actions: assign({ queued: ({ context }) => context.queued + 1, dirty: () => true }) } } },
    dirty: {
      on: {
        EDIT: { actions: assign({ queued: ({ context }) => context.queued + 1 }) },
        UPLOAD: 'uploading'
      }
    },
    uploading: {
      invoke: {
        src: 'push',
        input: ({ context }) => ({ queued: context.queued }),
        onDone: { target: 'clean', actions: assign({ queued: () => 0, dirty: () => false }) },
        onError: 'dirty'
      }
    }
  }
});
```

