import { setup, assign, fromPromise } from 'xstate';

interface Ctx { attempts: number; error: string | null }
type Ev = { type: 'CHANGE' } | { type: 'RETRY' } | { type: 'ACK' };

export const cappedSync = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    push: fromPromise<void, { n: number }>(async () => {
      // network call
    })
  },
  guards: {
    canRetry: ({ context }) => context.attempts < 3,
    hitCap: ({ context }) => context.attempts >= 3
  },
  actions: {
    bump: assign({ attempts: ({ context }) => context.attempts + 1 }),
    clear: assign({ attempts: () => 0, error: () => null }),
    setError: assign({ error: ({ event }) => ('error' in event ? String((event as { error: unknown }).error) : 'sync failed') })
  }
}).createMachine({
  id: 'cappedSync',
  context: { attempts: 0, error: null },
  initial: 'synced',
  states: {
    synced: { on: { CHANGE: 'uploading' } },
    uploading: {
      invoke: {
        src: 'push',
        input: ({ context }) => ({ n: context.attempts }),
        onDone: { target: 'synced', actions: 'clear' },
        onError: [
          { guard: 'hitCap', target: 'failed', actions: 'setError' },
          { target: 'retrying', actions: ['bump', 'setError'] }
        ]
      }
    },
    retrying: {
      on: {
        RETRY: [{ guard: 'canRetry', target: 'uploading' }, { target: 'failed' }]
      }
    },
    failed: {
      on: { ACK: { target: 'synced', actions: 'clear' } }
