import { setup, assign, fromPromise } from 'xstate';

interface Ctx { page: number; total: number }
type Ev =
  | { type: 'OPEN'; url: string }
  | { type: 'NEXT' }
  | { type: 'PREV' }
  | { type: 'GOTO'; page: number };

