import { setup, assign } from 'xstate';

interface Match { page: number; index: number }
interface Ctx { page: number; matches: Match[]; current: number }
type Ev =
  | { type: 'NEXT' }
  | { type: 'SEARCH'; matches: Match[] }
  | { type: 'NEXT_MATCH' }
  | { type: 'PREV_MATCH' };

export const m = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    nextPage: assign({ page: ({ context }) => context.page + 1 }),
    setMatches: assign({ matches: ({ event }) => (event.type === 'SEARCH' ? event.matches : []), current: () => 0 }),
    stepMatch: assign({
      current: ({ context, event }) => {
        if (context.matches.length === 0) return 0;
        const delta = event.type === 'NEXT_MATCH' ? 1 : -1;
        return (context.current + delta + context.matches.length) % context.matches.length;
      },
      page: ({ context, event }) => {
        if (context.matches.length === 0) return context.page;
        const delta = event.type === 'NEXT_MATCH' ? 1 : -1;
        const i = (context.current + delta + context.matches.length) % context.matches.length;
        return context.matches[i].page;
      }
    })
  }
}).createMachine({
  id: 'pdf',
  context: { page: 1, matches: [], current: 0 },
  initial: 'viewing',
  states: {
    viewing: {
      on: {
        NEXT: { actions: 'nextPage' },
        SEARCH: { actions: 'setMatches' },
        NEXT_MATCH: { actions: 'stepMatch' },
        PREV_MATCH: { actions: 'stepMatch' }
      }
    }
  }
});
