import { setup, assign } from 'xstate';

interface Ctx { holdUntil: number; heldSince: number }
type Ev = { type: 'HOLD'; slotId: string } | { type: 'EXTEND' } | { type: 'CONFIRM' } | { type: 'EXPIRE' };

const FIVE = 5 * 60_000;
const MAX = 30 * 60_000;

export const extendableHold = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: {
    UNTIL_EXPIRE: ({ context }: { context: Ctx }) => Math.max(0, context.holdUntil - Date.now())
  },
  guards: {
    canExtend: ({ context }) => context.holdUntil - context.heldSince + FIVE <= MAX
  },
  actions: {
    start: assign({
      heldSince: () => Date.now(),
      holdUntil: () => Date.now() + 15 * 60_000
    }),
    extend: assign({
      holdUntil: ({ context }) => context.holdUntil + FIVE
    })
  }
}).createMachine({
  id: 'extendableHold',
  context: { holdUntil: 0, heldSince: 0 },
  initial: 'idle',
  states: {
    idle: { on: { HOLD: { target: 'holding', actions: 'start' } } },
    holding: {
      after: { UNTIL_EXPIRE: 'expired' },
      on: {
        EXTEND: { guard: 'canExtend', target: 'holding', reenter: true, actions: 'extend' },
        CONFIRM: 'confirmed',
        EXPIRE: 'expired'
      }
    },
    confirmed: { type: 'final' },
    expired: { type: 'final' }
  }
});
